#version 330
// AI_PIPELINE_HOOK
// style_profile: minimal
// generated_with: langgraph_agent

uniform vec3 iResolution;
uniform float iTime;
uniform sampler2D iChannel0;  // 音频纹理

out vec4 FragColor;

// --- 伪随机哈希 ---
float hash21(vec2 p) {
    p = fract(p * vec2(234.34, 435.345));
    p += dot(p, p + 19.19);
    return fract(p.x * p.y);
}

// --- 2D 旋转 ---
vec2 rot(vec2 uv, float angle) {
    float s = sin(angle);
    float c = cos(angle);
    return vec2(uv.x * c - uv.y * s, uv.x * s + uv.y * c);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = (fragCoord - 0.5 * iResolution.xy) / iResolution.y;

    // --- 音频采样（分带） ---
    // 低频：节奏基底
    float audioLow = texture(iChannel0, vec2(0.05, 0.25)).r;
    // 中频：旋律
    float audioMid = texture(iChannel0, vec2(0.25, 0.5)).r;
    // 高频：细节
    float audioHigh = texture(iChannel0, vec2(0.5, 0.75)).r;

    // 圆舞曲脉冲：用时间模拟3/4拍强弱弱
    float beat = sin(iTime * 6.0);  // 约 180 BPM
    float pulse = 0.5 + 0.5 * beat;
    float waltzPhase = fract(iTime * 3.0);  // 3拍循环

    // --- 手势交互预留层 ---
    // 模拟手势位置（实际使用时替换为真实手势输入）
    vec2 gesturePos = vec2(0.3 + 0.3 * sin(iTime * 0.5), 0.2 + 0.2 * cos(iTime * 0.7));
    float gestureRadius = 0.15 + 0.05 * audioMid;

    // --- 小元素系统：粒子网格 ---
    vec3 color = vec3(0.0);
    float gridSize = 12.0;

    // 主粒子网格
    for (float i = 0.0; i < gridSize; i++) {
        for (float j = 0.0; j < gridSize; j++) {
            vec2 cellPos = vec2(i, j) / gridSize;
            vec2 cellCenter = cellPos + 0.5 / gridSize;

            // 映射到屏幕坐标
            vec2 pos = cellCenter * 2.0 - 1.0;
            pos.x *= iResolution.x / iResolution.y;

            // 每个粒子的随机偏移
            float seed = hash21(vec2(i, j));
            float seed2 = hash21(vec2(i + 100.0, j + 200.0));

            // 音频驱动：低频影响位置偏移幅度
            float offsetScale = 0.03 + 0.06 * audioLow;
            // 中频影响旋转
            float rotAngle = iTime * (0.2 + 0.5 * seed) + audioMid * 3.0;
            // 高频影响闪烁
            float twinkle = 0.7 + 0.3 * sin(iTime * 10.0 + seed * 100.0 + audioHigh * 20.0);

            // 圆舞曲节拍影响：强弱弱
            float beatEffect = 1.0;
            float phaseOffset = fract(seed * 3.0);
            if (phaseOffset < 0.33) beatEffect = 0.6 + 0.4 * pulse;
            else if (phaseOffset < 0.66) beatEffect = 0.8 + 0.2 * pulse;
            else beatEffect = 0.5 + 0.5 * pulse;

            // 粒子位置偏移（随音乐起舞）
            vec2 offset = vec2(
                sin(iTime * (1.0 + seed * 2.0) + seed * 6.28),
                cos(iTime * (1.2 + seed2 * 2.0) + seed2 * 6.28)
            ) * offsetScale * beatEffect;

            // 手势交互影响：靠近手势的粒子被推开
            vec2 gestureDelta = pos - gesturePos;
            float distToGesture = length(gestureDelta);
            float gestureInfluence = smoothstep(gestureRadius, 0.0, distToGesture);
            offset += normalize(gestureDelta) * gestureInfluence * 0.05 * audioMid;

            vec2 finalPos = pos + offset;

            // 粒子大小
            float size = 0.012 + 0.008 * seed + 0.005 * audioMid;
            size *= beatEffect;

            // 粒子形状：圆点 + 小星形变化
            float d = length(uv - finalPos);

            // 颜色：根据种子和音频变化
            vec3 particleColor = vec3(
                0.3 + 0.7 * seed,
                0.2 + 0.8 * seed2,
                0.5 + 0.5 * hash21(vec2(i + j, i * j))
            );

            // 中频影响色调偏移
            particleColor = mix(particleColor, 
                vec3(0.8, 0.4, 0.6) * (0.5 + 0.5 * audioMid), 
                0.3 * audioMid);

            // 高频影响亮度
            float brightness = twinkle * (0.8 + 0.4 * audioHigh);

            // 绘制粒子
            float particle = smoothstep(size, 0.0, d);
            color += particle * particleColor * brightness;

            // 粒子外围辉光
            float glow = smoothstep(size * 3.0, size, d) * 0.15 * audioHigh;
            color += glow * particleColor * brightness;
        }
    }

    // --- 第二层：随机散布的小点（更稀疏，更亮） ---
    for (int k = 0; k < 40; k++) {
        float fi = float(k);
        float seed = hash21(vec2(fi, fi * 3.0));
        float seed2 = hash21(vec2(fi * 7.0, fi * 11.0));

        vec2 pos = vec2(
            (seed * 2.0 - 1.0) * (iResolution.x / iResolution.y),
            seed2 * 2.0 - 1.0
        );

        // 音频驱动运动
        float moveSpeed = 0.3 + 0.7 * seed;
        float angle = seed * 6.28 + iTime * (0.1 + 0.2 * seed);
        float radius = 0.1 + 0.3 * seed + 0.1 * audioLow;

        vec2 offset = vec2(cos(angle), sin(angle)) * radius * (0.5 + 0.5 * sin(iTime * moveSpeed + seed * 10.0));

        // 手势交互
        vec2 gestureDelta = pos + offset - gesturePos;
        float distToGesture = length(gestureDelta);
        float gestureInfluence = smoothstep(gestureRadius * 1.5, 0.0, distToGesture);
        offset += normalize(gestureDelta) * gestureInfluence * 0.08 * audioMid;

        vec2 finalPos = pos + offset;

        float d = length(uv - finalPos);
        float size = 0.006 + 0.004 * seed + 0.003 * audioHigh;

        vec3 col = vec3(
            0.6 + 0.4 * sin(seed * 6.28 + audioMid * 2.0),
            0.3 + 0.7 * cos(seed2 * 6.28 + audioMid * 1.5),
            0.8 + 0.2 * sin((seed + seed2) * 6.28 + audioHigh * 3.0)
        );

        float particle = smoothstep(size, 0.0, d);
        color += particle * col * (0.6 + 0.4 * audioHigh);
    }

    // --- 手势交互可视化（半透明指示圈） ---
    float gestureDist = length(uv - gesturePos);
    float gestureRing = smoothstep(0.005, 0.0, abs(gestureDist - gestureRadius));
    gestureRing += smoothstep(0.003, 0.0, abs(gestureDist - gestureRadius * 0.6)) * 0.5;
    color += gestureRing * vec3(0.3, 0.6, 1.0) * (0.3 + 0.3 * audioMid);

    // --- 背景：柔和的渐变 ---
    vec3 bg = vec3(0.02, 0.02, 0.04);
    bg += vec3(0.01, 0.005, 0.02) * sin(iTime * 0.3 + uv.y * 2.0);

    // 背景微光随音乐变化
    bg += vec3(0.01, 0.005, 0.01) * audioLow;

    vec3 finalColor = mix(bg, color, min(color.r + color.g + color.b, 1.0));

    // 轻微色调映射
    finalColor = finalColor / (finalColor + vec3(1.0));

    fragColor = vec4(finalColor, 1.0);
}

void main() {
    mainImage(FragColor, gl_FragCoord.xy);
}

#version 330
// AI_PIPELINE_HOOK
// style_profile: minimal
// generated_with: langgraph_agent
uniform vec3 iResolution;
uniform float iTime;
uniform sampler2D iChannel0;

out vec4 FragColor;

float hash21(vec2 p) {
    p = fract(p * vec2(234.34, 435.345));
    p += dot(p, p + 19.19);
    return fract(p.x * p.y);
}

float hash(vec2 p) {
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
}

float smoothNoise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

float sdCircle(vec2 p, float r) {
    return length(p) - r;
}

float sdStar(vec2 p, float r, float n) {
    float a = atan(p.y, p.x);
    float seg = 3.14159 * 2.0 / n;
    a = mod(a - seg * 0.5, seg) - seg * 0.5;
    float d = length(p);
    float rad = r * cos(a) / cos(mod(a, seg) - seg * 0.5);
    return d - rad * 0.8;
}

float sdDiamond(vec2 p, float r) {
    float d = abs(p.x) + abs(p.y);
    return d - r;
}

float sdHexagon(vec2 p, float r) {
    vec2 q = abs(p);
    return max(q.x * 0.866025 + q.y * 0.5, q.y) - r;
}

float shape(vec2 p, float r, float type) {
    if (type < 0.25) return sdCircle(p, r);
    else if (type < 0.5) return sdStar(p, r, 5.0);
    else if (type < 0.75) return sdDiamond(p, r);
    else return sdHexagon(p, r);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = (fragCoord - 0.5 * iResolution.xy) / min(iResolution.x, iResolution.y);

    vec2 audioUV = fragCoord / iResolution.xy;
    vec4 audioTex = texture(iChannel0, audioUV);

    float bass = audioTex.x * 0.6 + 0.4 * (0.5 + 0.5 * sin(iTime * 1.5));
    float mid = audioTex.y * 0.5 + 0.5 * (0.5 + 0.5 * sin(iTime * 2.3 + 1.2));
    float treble = audioTex.z * 0.4 + 0.6 * (0.5 + 0.5 * sin(iTime * 3.7 + 2.8));

    float gesture = audioTex.w;

    float gridSize = 16.0;
    vec2 gridUV = uv * gridSize;
    vec2 cellId = floor(gridUV);
    vec2 cellPos = fract(gridUV) - 0.5;

    float seed = hash21(cellId);
    float typeSeed = hash21(cellId + vec2(100.0));
    float phase = hash21(cellId + vec2(200.0)) * 6.283;

    float shapeType = typeSeed;

    float bassOffset = bass * 0.15;
    vec2 offset = vec2(
        sin(iTime * 1.2 + phase + bass * 4.0) * bassOffset,
        cos(iTime * 1.5 + phase * 0.7 + bass * 3.0) * bassOffset
    );

    float sizeBase = 0.12 + seed * 0.15;
    float sizeMod = mid * 0.2;
    float size = sizeBase + sizeMod;

    float glow = treble * 0.8 + 0.2;

    float waltzBeat = sin(iTime * 2.0 * 3.14159 * 1.0) * 0.5 + 0.5;
    float pulse = bass * 0.7 + waltzBeat * 0.3;

    vec2 p = cellPos + offset;
    float d = shape(p, size, shapeType);

    vec3 col1 = vec3(0.1, 0.6, 0.9);
    vec3 col2 = vec3(0.9, 0.3, 0.5);
    vec3 col3 = vec3(0.2, 0.8, 0.6);
    vec3 col4 = vec3(0.9, 0.7, 0.1);

    vec3 baseColor = col1;
    if (typeSeed < 0.25) baseColor = col1;
    else if (typeSeed < 0.5) baseColor = col2;
    else if (typeSeed < 0.75) baseColor = col3;
    else baseColor = col4;

    float brightness = 1.2 + bass * 0.8 + mid * 0.4;

    float glowIntensity = glow * 0.6;
    float edgeGlow = smoothstep(size - 0.02, size, abs(d)) * glowIntensity;

    float shapeMask = 1.0 - smoothstep(0.0, 0.03, d);
    float shapeGlow = exp(-abs(d) * 8.0) * glowIntensity;

    vec3 color = vec3(0.0);

    color += baseColor * shapeMask * brightness * (0.8 + pulse * 0.4);
    color += baseColor * shapeGlow * brightness;
    color += vec3(1.0) * edgeGlow * treble * 1.5;

    float extraSeed = hash21(cellId + vec2(50.0, 50.0));
    if (extraSeed > 0.3) {
        vec2 extraOffset = vec2(
            sin(iTime * 2.0 + extraSeed * 10.0 + bass * 3.0) * 0.08,
            cos(iTime * 2.3 + extraSeed * 7.0 + bass * 2.5) * 0.08
        );
        float extraSize = 0.03 + extraSeed * 0.06 + mid * 0.05;
        float extraType = hash21(cellId + vec2(300.0));
        float d2 = shape(cellPos + extraOffset, extraSize, extraType);
        float extraMask = 1.0 - smoothstep(0.0, 0.02, d2);
        float extraGlow = exp(-abs(d2) * 12.0) * glowIntensity * 0.5;

        vec3 extraColor = mix(col3, col4, extraSeed);
        color += extraColor * extraMask * brightness * 0.7;
        color += extraColor * extraGlow * 0.8;
    }

    color += vec3(0.3, 0.5, 0.8) * gesture * 0.3;

    vec3 bg = vec3(0.02, 0.03, 0.05);
    color = mix(bg, color, 1.0 - exp(-length(color) * 2.0));

    color *= 1.3;

    color = color / (color + vec3(1.0));
    color = pow(color, vec3(1.0 / 2.2));

    fragColor = vec4(color, 1.0);
}

void main() {
    vec4 color;
    mainImage(color, gl_FragCoord.xy);
    FragColor = color;
}

