#version 330
// AI_PIPELINE_HOOK
// style_profile: minimal
// generated_with: langgraph_agent

uniform vec3 iResolution;
uniform float iTime;
uniform sampler2D iChannel0;

out vec4 FragColor;

// 音频采样辅助函数
float getAudio(float t) {
    return texture(iChannel0, vec2(t, 0.0)).r;
}

// 伪随机哈希
float hash21(vec2 p) {
    p = fract(p * vec2(234.34, 435.345));
    p += dot(p, p + 19.19);
    return fract(p.x * p.y);
}

// 噪声
float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);
    float a = hash21(i);
    float b = hash21(i + vec2(1.0, 0.0));
    float c = hash21(i + vec2(0.0, 1.0));
    float d = hash21(i + vec2(1.0, 1.0));
    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
}

void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = (fragCoord - 0.5 * iResolution.xy) / min(iResolution.x, iResolution.y);

    // 音频采样 - 分带
    float bass = getAudio(0.05);      // 低频
    float mid = getAudio(0.25);       // 中频
    float high = getAudio(0.5);       // 高频
    float energy = (bass + mid + high) * 0.5;

    // 圆舞曲3/4拍脉冲 - BPM ~190
    float beat = sin(iTime * 3.14159 * 3.2) * 0.5 + 0.5;  // 约192 BPM的3拍循环
    float waltzPhase = fract(iTime * 3.2);  // 3/4拍相位
    float pulse = pow(1.0 - abs(waltzPhase - 0.5) * 2.0, 4.0);  // 脉冲形状

    // 粒子星系参数
    float particleCount = 60.0;
    float minDist = 1.0;
    vec3 col = vec3(0.0);

    // 低频驱动星系旋转
    float rotAngle = iTime * 0.15 + bass * 0.5;
    float cosA = cos(rotAngle);
    float sinA = sin(rotAngle);

    // 中频驱动粒子活跃度
    float activity = 0.5 + mid * 0.8;

    for (float i = 0.0; i < particleCount; i += 1.0) {
        // 每个粒子的随机种子
        float seed = i / particleCount;
        vec2 seed2 = vec2(seed, seed * 0.731);

        // 粒子在星系中的轨道位置
        float radius = 0.1 + hash21(seed2 + 10.0) * 0.8;
        float angle = hash21(seed2 + 20.0) * 6.2832 + iTime * (0.2 + radius * 0.3) * (1.0 + bass * 0.5);

        // 轨道半径受低频调制
        radius += sin(iTime * 1.6 + seed * 6.2832) * 0.05 * bass;

        // 粒子位置
        vec2 pos = vec2(cos(angle), sin(angle)) * radius;

        // 应用星系旋转
        vec2 rotPos = vec2(
            pos.x * cosA - pos.y * sinA,
            pos.x * sinA + pos.y * cosA
        );

        // 中频驱动粒子径向抖动
        float jitter = noise(vec2(seed * 10.0 + iTime * 0.5, 0.0)) * mid * 0.15;
        rotPos += vec2(jitter);

        // 3/4拍脉冲影响粒子大小
        float sizeBase = 0.02 + hash21(seed2 + 30.0) * 0.04;
        float sizeMod = 1.0 + pulse * 0.6 * (0.7 + 0.3 * sin(seed * 6.2832));
        float particleSize = sizeBase * sizeMod * (0.8 + activity * 0.4);

        // 粒子到当前像素的距离
        float d = length(rotPos - uv);
        float glow = particleSize / (d + 0.001);

        // 粒子颜色 - 中频主导色调
        vec3 color1 = vec3(0.2, 0.6, 0.9);  // 冷蓝
        vec3 color2 = vec3(0.9, 0.4, 0.6);  // 暖粉
        vec3 color3 = vec3(0.1, 0.8, 0.7);  // 青绿

        float hueShift = sin(seed * 6.2832 + iTime * 0.3) * 0.5 + 0.5;
        vec3 particleColor = mix(color1, color2, hueShift);
        particleColor = mix(particleColor, color3, sin(iTime * 0.2 + seed) * 0.3 + 0.3);

        // 高频影响颜色亮度
        particleColor *= (0.8 + high * 0.6);

        // 中频影响粒子辉光强度
        float midGlow = 0.5 + mid * 1.2;
        col += glow * particleColor * midGlow * 0.15;
    }

    // 星系中心辉光 - 受低频和能量影响
    float centerDist = length(uv);
    float centerGlow = 0.08 / (centerDist + 0.05);
    vec3 centerColor = vec3(0.3, 0.5, 0.9) * (0.5 + bass * 0.8);
    col += centerGlow * centerColor * 0.3;

    // 背景星尘 - 受高频影响
    vec2 st = uv * 15.0 + iTime * 0.02;
    float dust = noise(st);
    float dustThreshold = 0.55 - high * 0.15;
    if (dust > dustThreshold) {
        float brightness = (dust - dustThreshold) / (1.0 - dustThreshold) * 0.3;
        col += vec3(brightness * 0.8);
    }

    // 色调映射
    col = col / (col + 1.0);
    col = pow(col, vec3(0.8));

    // 暗角
    float vignette = 1.0 - dot(uv, uv) * 0.6;
    col *= vignette;

    fragColor = vec4(col, 1.0);
}

void main() {
    mainImage(FragColor, gl_FragCoord.xy);
}

