//   - 频率基本固定，仅受音频微弱调制（< 5% 偏移）
//   - 多层波形叠加，每层的振幅 = 不同频段音频采样值
// ============================================================

uniform vec3 iResolution;
uniform float iTime;
uniform sampler2D iChannel0;

out vec4 FragColor;

// ---- 安全音频采样 ----
float sampleAudio(float t) {
    return texture(iChannel0, vec2(clamp(t, 0.0, 1.0), 0.0)).r;
}

float absSample(float t) {
    return abs(sampleAudio(t));
}

// ---- 平滑阶梯 ----
float smoothStep(float edge0, float edge1, float x) {
    float t = clamp((x - edge0) / (edge1 - edge0), 0.0, 1.0);
    return t * t * (3.0 - 2.0 * t);
}

// ---- 主入口 ----
void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = fragCoord / iResolution.xy;
    float aspect = iResolution.x / iResolution.y;
    vec2 p = (uv - 0.5) * vec2(aspect, 1.0);

    // ============================================================
    // 1. 音频采样 — 分带提取力度值
    // ============================================================
    float bass   = absSample(0.05);
    float mid    = absSample(0.35);
    float treble = absSample(0.72);

    // 整体能量（用于背景氛围）
    float energy = 0.0;
    for (int i = 0; i < 16; i++) {
        energy += absSample(float(i) / 16.0);
    }
    energy /= 16.0;

    // 随时间微移采样点，增加动态丰富度（频率微调来源）
    float bassShift   = absSample(0.05 + 0.01 * sin(iTime * 0.07));
    float midShift    = absSample(0.35 + 0.01 * sin(iTime * 0.11));
    float trebleShift = absSample(0.72 + 0.01 * sin(iTime * 0.13));

    // 取 max 保留峰值
    bass   = max(bass, bassShift);
    mid    = max(mid, midShift);
    treble = max(treble, trebleShift);

    // ============================================================
    // 2. 背景 — 多瑙河深蓝渐变
    // ============================================================
    vec3 bgTop    = vec3(0.012, 0.015, 0.035);
    vec3 bgBottom = vec3(0.035, 0.045, 0.080);
    vec3 bg = mix(bgBottom, bgTop, uv.y);
    vec3 color = bg;

    // ============================================================
    // 3. 横向波形 — 音频力度 → 波形振幅
    //    频率固定（仅受音频<5%微调）
