    float xPos = uv.x * 2.0 - 1.0;  // [-1, 1]
    vec3 waveColor = vec3(0.28, 0.58, 1.00);

    // --- 3a. 主波形（低频轮廓） ---
    {
        // 振幅 = 音频力度 × 基础振幅
        float amplitude = 0.20 * bass;

        // 频率：固定基频 + 极微弱的音频调制（<5%）
        float baseFreq = 4.0;
        float freqMod = 1.0 + 0.04 * bass;  // 仅 4% 偏移
        float freq = baseFreq * freqMod;

        // 相位：固定 + 微弱音频影响
        float phaseOffset = 0.02 * mid * sin(iTime * 0.3);

        // 波形计算：振幅由音频力度控制
        float wave = sin(xPos * freq * 3.14159 + iTime * 0.40 + phaseOffset);

        // 垂直位置 = 振幅
        float yPos = amplitude * wave;

        // 绘制线条
        float dist = abs(p.y - yPos);
        float lineWidth = 0.003 + 0.005 * bass;
        float line = 1.0 - smoothStep(0.0, lineWidth, dist);
        vec3 lineCol = waveColor * (1.0 + treble * 0.6);
        color = mix(color, lineCol, line * 0.85);

        // 辉光
        float glow = exp(-dist * 45.0) * (0.08 + 0.15 * bass);
        color += waveColor * glow * 0.35;
    }

    // --- 3b. 辅波形（中频细节 × 3层） ---
    for (int i = 0; i < 3; i++) {
        float fi = float(i);

        // 每层振幅由不同音频力度控制
        float amplitude = (0.04 + 0.08 * mid) * (1.0 - fi * 0.15);

        // 频率：基础频率递增 + 微弱音频调制
        float baseFreq = 5.5 + fi * 2.5;
        float freqMod = 1.0 + 0.03 * (mid + treble * 0.5);
        float freq = baseFreq * freqMod;

        // 相位偏移（层间错开）
        float phase = fi * 1.05 + 0.01 * treble * sin(iTime * (0.5 + fi * 0.2));

        float wave = sin(xPos * freq * 3.14159 + iTime * (0.50 + fi * 0.12) + phase);
        float yPos = amplitude * wave;

        float dist = abs(p.y - yPos);
        float lineWidth = 0.0015 + 0.0025 * (1.0 - fi * 0.2);
        float line = 1.0 - smoothStep(0.0, lineWidth, dist);

        vec3 col = mix(vec3(0.22, 0.48, 0.90), vec3(0.45, 0.72, 1.00), fi / 3.0);
        color = mix(color, col, line * 0.45 * (0.5 + 0.5 * treble));

        float glow = exp(-dist * 35.0) * 0.06;
        color += col * glow;
    }

    // ============================================================
