        float densityAmp = 0.15 + 0.30 * bass;

        // 频率固定 + 微调
        float ringFreq = 25.0 + 2.0 * bass;
        float density = sin(radius * ringFreq + angle * 4.0 + iTime * 0.4) * 0.5 + 0.5;
        density *= sin(radius * 18.0 - angle * 3.0 + iTime * 0.6) * 0.5 + 0.5;

        float ring = density * exp(-radius * 2.5) * densityAmp;

        vec3 ringColor = mix(vec3(0.12, 0.35, 0.78), vec3(0.35, 0.65, 1.00), mid);
        color += ringColor * ring;
    }

    // ============================================================
    // 5. 底部频谱条 — 高度由音频力度直接控制
    // ============================================================
    {
        float barRegion = smoothStep(0.06, 0.0, abs(p.y + 0.44));
        if (barRegion > 0.0) {
            float barCount = 16.0;
            float barIdx = floor((xPos + 1.0) * 0.5 * barCount);
            float barPos = (barIdx + 0.5) / barCount * 2.0 - 1.0;
            float barCenter = abs(xPos - barPos);

            float freqT = barIdx / barCount;
            // 振幅 = 音频力度
            float ampVal = absSample(0.02 + freqT * 0.96);

            float barHeight = ampVal * 0.08;

            float inBar = 1.0 - smoothStep(0.0, 0.010, barCenter);
            float inHeight = 1.0 - smoothStep(0.0, barHeight, abs(p.y + 0.44));
            float barMask = inBar * inHeight * barRegion;

            vec3 barColor = mix(vec3(0.10, 0.25, 0.60), vec3(0.30, 0.60, 1.00), freqT);
            color = mix(color, barColor, barMask * 0.40);
        }
