```glsl
#version 330
// AI_PIPELINE_HOOK
// style_profile: minimal
// generated_with: langgraph_agent

// ============================================================
// Blue Danube — 主包络 + 距离衰减平滑振幅
// 核心:
//   1. 音频采样 → 双边滑动平均滤波（平滑）
//   2. 中心主包络 = 滤波后的音频能量
//   3. 辅波形振幅按距中心距离平滑衰减
//   4. 整体柔和、自然、不硬绑
// ============================================================

uniform vec3 iResolution;
uniform float iTime;
uniform sampler2D iChannel0;

out vec4 FragColor;

// ---- 安全音频采样 ----
float sampleAudio(float t) {
    return texture(iChannel0, vec2(clamp(t, 0.0, 1.0), 0.0)).r;
}

float absSample(float t) {
    return abs(sampleAudio(t));
}

// ---- 平滑阶梯 ----
float smoothStep(float edge0, float edge1, float x) {
    float t = clamp((x - edge0) / (edge1 - edge0), 0.0, 1.0);
    return t * t * (3.0 - 2.0 * t);
}

// ---- 双边滑动平均滤波（5 点） ----
float smoothAudio(float t) {
    float sum = 0.0;
    float weights = 0.0;
    for (int i = -2; i <= 2; i++) {
        float fi = float(i);
        float w = 1.0 - abs(fi) * 0.2; // 三角权重
        sum += absSample(t + fi * 0.005) * w;
        weights += w;
    }
    return sum / weights;
}

// ---- 主入口 ----
void mainImage(out vec4 fragColor, in vec2 fragCoord) {
    vec2 uv = fragCoord / iResolution.xy;
    float aspect = iResolution.x / iResolution.y;
    vec2 p = (uv - 0.5) * vec2(aspect, 1.0);
    float xPos = uv.x * 2.0 - 1.0; // [-1, 1]
    float radius = length(p);

    // ============================================================
    // 1. 音频采样 → 平滑滤波 → 主包络提取
    // ============================================================
    // 主包络：以中心位置（t≈0.5）的平滑音频值为基准
    float mainEnvelope = smoothAudio(0.50);
    // 辅助包络：左右两侧采样，用于辅波形的距离衰减
    float leftEnvelope  = smoothAudio(0.30);
    float rightEnvelope = smoothAudio(0.70);
    float bassEnvelope  = smoothAudio(0.05);
    float trebleEnvelope = smoothAudio(0.80);

    // 全局能量（用于背景氛围）
    float energy = 0.0;
    for (int i = 0; i < 12; i++) {
        energy += smoothAudio(float(i) / 12.0);
    }
    energy /= 12.0;

    // ============================================================
    // 2. 背景 — 深蓝渐变
    // ============================================================
    vec3 bgTop    = vec3(0.010, 0.012, 0.030);
    vec3 bgBottom = vec3(0.030, 0.040, 0.070);
    vec3 bg = mix(bgBottom, bgTop, uv.y);
    vec3 color = bg;

    // ============================================================
    // 3. 主波形（中心主包络）
    //    振幅 = 主包络 × 基础系数
    //    频率几乎固定，仅受 < 3% 微调
    // ============================================================
    vec3 waveColor = vec3(0.28, 0.58, 1.00);

    // --- 3a. 主波形（中心包络驱动） ---
    {
        // 主包络控制振幅
        float amplitude = 0.18 * mainEnvelope;

        // 频率：固定 + 极微调制
        float freq = 4.0 * (1.0 + 0.03 * mainEnvelope);
        float phase = 0.02 * bassEnvelope * sin(iTime * 0.2);

        float wave = sin(xPos * freq * 3.14159 + iTime * 0.40 + phase);
        float yPos = amplitude * wave;

        float dist = abs(p.y - yPos);
        float lineWidth = 0.003 + 0.005 * mainEnvelope;
        float line = 1.0 - smoothStep(0.0, lineWidth, dist);
        vec3 lineCol = waveColor * (0.9 + 0.5 * mainEnvelope);
        color = mix(color, lineCol, line * 0.85);

        float glow = exp(-dist * 45.0) * (0.06 + 0.18 * mainEnvelope);
        color += waveColor * glow * 0.35;
    }

    // --- 3b. 辅波形 × 3 层（距离主包络越远，振幅越小） ---
    for (int i = 0; i < 3; i++) {
        float fi = float(i);

        // 距离因子：越远的层，振幅衰减越明显
        float distFactor = 1.0 - fi * 0.25;

        // 包络选择：越靠近中心的层使用主包络，越远的层使用侧边包络
        float envelopeMix = 1.0 - fi * 0.20;
        float layerEnvelope = mix(leftEnvelope * rightEnvelope, mainEnvelope, envelopeMix);

        // 振幅 = 包络 × 距离衰减
        float amplitude = (0.03 + 0.07 * layerEnvelope) * distFactor;

        // 频率
        float baseFreq = 5.5 + fi * 2.0;
        float freq = baseFreq * (1.0 + 0.02 * layerEnvelope);
        float phase = fi * 1.05 + 0.01 * trebleEnvelope * sin(iTime * (0.5 + fi * 0.2));

        float wave = sin(xPos * freq * 3.14159 + iTime * (0.50 + fi * 0.12) + phase);
        float yPos = amplitude * wave;

        float dist = abs(p.y - yPos);
        float lineWidth = 0.0015 + 0.0025 * distFactor;
        float line = 1.0 - smoothStep(0.0, lineWidth, dist);

        vec3 col = mix(vec3(0.20, 0.45, 0.85), vec3(0.40, 0.68, 1.00), fi / 3.0);
        float alpha = 0.40 * distFactor * (0.5 + 0.5 * layerEnvelope);
        color = mix(color, col, line * alpha);

        float glow = exp(-dist * 35.0) * 0.05 * distFactor;
        color += col * glow;
    }

    // ============================================================
    // 4. 径向环 — 包络控制密度，距离中心衰减
    // ============================================================
    {
        float angle = atan(p.y, p.x);

        // 环的密度由主包络控制
        float densityAmp = 0.10 + 0.25 * mainEnvelope;

        float ringFreq = 22.0 + 3.0 * bassEnvelope;
        float density = sin(radius * ringFreq + angle * 4.0 + iTime * 0.35) * 0.5 + 0.5;
        density *= sin(radius * 16.0 - angle * 3.0 + iTime * 0.55) * 0.5 + 0.5;

        // 距离衰减（中心强，边缘弱）
        float radiusFalloff = exp(-radius * 2.8) * (1.0 - radius * 0.3);
        float ring = density * radiusFalloff * densityAmp;

        vec3 ringColor = mix(vec3(0.10, 0.30, 0.72), vec3(0.30, 0.60, 1.00), mainEnvelope);
        color += ringColor * ring;
    }

    // ============================================================
    // 5. 底部频谱条 — 平滑包络控制高度
    // ============================================================
    {
        float barRegion = smoothStep(0.06, 0.0, abs(p.y + 0.44));
        if (barRegion > 0.0) {
            float barCount = 16.0;
            float barIdx = floor((xPos + 1.0) * 0.5 * barCount);
            float barPos = (barIdx + 0.5) / barCount * 2.0 - 1.0;
            float barCenter = abs(xPos - barPos);

            float freqT = barIdx / barCount;
            // 使用平滑采样
            float ampVal = smoothAudio(0.02 + freqT * 0.96);

            float barHeight = ampVal * 0.07;

            float inBar = 1.0 - smoothStep(0.0, 0.010, barCenter);
            float inHeight = 1.0 - smoothStep(0.0, barHeight, abs(p.y + 0.44));
            float barMask = inBar * inHeight * barRegion;

            vec3 barColor = mix(vec3(0.08, 0.22, 0.55), vec3(0.28, 0.58, 1.00), freqT);
            color = mix(color, barColor, barMask * 0.40);
        }
    }

    // ============================================================
    // 6. 星点 — 高频包络控制
    // ============================================================
    {
        vec2 gridId = floor(p * 22.0);
        vec2 gridPos = fract(p * 22.0) - 0.5;
        float pointDist = length(gridPos);

        float hash = fract(sin(dot(gridId, vec2(12.9898, 78.233))) * 43758.5453);

        float brightness = smoothStep(0.04, 0.0, pointDist);
        float twinkle = sin(hash * 100.0 + iTime * (2.0 + trebleEnvelope * 4.0)) * 0.5 + 0.5;
        brightness *= twinkle * trebleEnvelope * 0.5;
        brightness *= smoothStep(0.35, 0.0, abs(p.y));

        color += vec3(0.48, 0.70, 1.00) * brightness * 0.25;
    }

    // ============================================================
    // 7. 中心柔光 + 暗角
    // ============================================================
    float centerGlow = exp(-radius * 3.2) * energy * 0.22;
    color += vec3(0.10, 0.32, 0.68) * centerGlow;

    float vignette = 1.0 - 0.20 * radius * radius;
    color *= vignette;
    color = clamp(color, 0.0, 1.0);

    fragColor = vec4(color, 1.0);
}

// ---- 双入口兼容 ----
void main() {
    mainImage(FragColor, gl_FragCoord.xy);
}
